// ── STEP 1: INGEST ──
const raw = $json.body || $json || {};

function uuidV4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
const sid = uuidRe.test(String(raw.session_id || '')) ? raw.session_id : uuidV4();
const msg = String(raw.message || raw.clean_msg || '').trim() || 'Hello';
const turn = Number(raw.turn_index || 1);

return [{ json: {
  session_id: sid,
  turn_index: turn,
  user_message: msg,
  context: raw.context || { language: 'en', canton: 'ZH' },
  ingested_at: new Date().toISOString()
}}];

// ── STEP 2: PERSONALITY DETECTION (Heuristic + NVIDIA API fallback) ──
const d = $input.first().json;
const text = String(d.user_message || '').toLowerCase();

function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

function heuristicOcean(text) {
  let O = 0, C = 0, E = 0, A = 0, N = 0;
  const pos = (text.match(/(good|calm|grateful|thank|appreciate|better|hopeful|peace|relaxed|happy|great|awesome|wonderful|fantastic|love|enjoy|excited)/g) || []).length;
  const neg = (text.match(/(low|sad|anxious|worried|stress|overwhelmed|tired|panic|afraid|lonely|depressed|frustrated|angry|upset|hurt|scared|terrible|awful|horrible)/g) || []).length;
  const soc = (text.match(/(you|we|together|friends|family|talk|share|people|connect|relationship)/g) || []).length;
  const exp = (text.match(/(new|explore|learn|curious|idea|possibility|creative|wonder|imagine|discover)/g) || []).length;
  const str = (text.match(/(plan|organize|routine|schedule|step|priority|focus|goal|structure|discipline)/g) || []).length;
  const greet = (text.match(/(hi|hello|hey|how are you|what's up|good morning|good evening)/g) || []).length;

  N = clamp((neg - pos) * 0.15, -0.8, 0.8);
  E = clamp((soc * 0.1) + (pos * 0.05) - (neg * 0.05) + (greet * 0.2), -0.7, 0.7);
  A = clamp((pos * 0.08) + (soc * 0.05) + (greet * 0.1), -0.5, 0.8);
  O = clamp(exp * 0.15, -0.3, 0.8);
  C = clamp(str * 0.14, -0.4, 0.8);

  return { O: clamp(O,-1,1), C: clamp(C,-1,1), E: clamp(E,-1,1), A: clamp(A,-1,1), N: clamp(N,-1,1) };
}

let ocean = heuristicOcean(text);
let apiStatus = 'heuristic';
let apiError = null;

// Try NVIDIA API if available
try {
  const apiKey = process.env.NVIDIA_API_KEY || '';
  const apiUrl = process.env.NVIDIA_API_URL || 'https://integrate.api.nvidia.com/v1/chat/completions';
  const model = process.env.NVIDIA_MODEL || 'google/gemma-3-12b-it';

  if (apiKey && apiKey.length > 10) {
    const prompt = `Analyze this text for OCEAN personality traits. Return ONLY a JSON object with keys O, C, E, A, N (each -1.0 to 1.0).\nText: "${text.slice(0, 500)}"`;
    const resp = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model, messages: [{ role: 'user', content: prompt }], temperature: 0.3, max_tokens: 100 })
    });
    if (resp.ok) {
      const body = await resp.json();
      const raw = body.choices?.[0]?.message?.content || '';
      const m = raw.match(/\{[^}]+\}/);
      if (m) {
        const parsed = JSON.parse(m[0]);
        if (typeof parsed.O === 'number') {
          ocean = { O: clamp(parsed.O,-1,1), C: clamp(parsed.C||0,-1,1), E: clamp(parsed.E||0,-1,1), A: clamp(parsed.A||0,-1,1), N: clamp(parsed.N||0,-1,1) };
          apiStatus = 'nvidia';
        }
      }
    } else {
      apiError = `API ${resp.status}`;
    }
  }
} catch (e) {
  apiError = e.message;
}

return [{ json: {
  ...d,
  ocean: ocean,
  detection: {
    api_status: apiStatus,
    error: apiError,
    ocean: ocean,
    confidence: { O: 0.5, C: 0.5, E: 0.5, A: 0.5, N: 0.5 }
  }
}}];

// ── STEP 3: REGULATION (Zurich Model mapping) ──
const d = $input.first().json;
const ocean = d.ocean || { O:0, C:0, E:0, A:0, N:0 };

const promptMap = {
  O: { high: 'Invite exploration and novelty', low: 'Focus on familiar topics; reduce novelty' },
  C: { high: 'Provide organized, structured guidance', low: 'Keep flexible, relaxed, and spontaneous' },
  E: { high: 'Maintain an energetic, sociable tone', low: 'Adopt a calm, low-key style with reflective space' },
  A: { high: 'Show warmth, empathy, and collaboration', low: 'Use a neutral, matter-of-fact stance' },
  N: { high: 'Reassure stability and confidence', low: 'Offer extra comfort; acknowledge anxieties' }
};

const directives = [];
for (const [trait, val] of Object.entries(ocean)) {
  if (Math.abs(val) > 0.1) {
    const dir = val > 0 ? promptMap[trait]?.high : promptMap[trait]?.low;
    if (dir) directives.push(dir);
  }
}

if (directives.length === 0) {
  directives.push('Be warm, attentive, and supportive');
  directives.push('Ask open-ended questions to understand the user better');
}

return [{ json: {
  ...d,
  directives: directives,
  regulation: {
    directive_count: directives.length,
    zurich_applied: true
  }
}}];

// ── STEP 4: GENERATE RESPONSE (Directive-aware heuristic + NVIDIA API) ──
const d = $input.first().json;
const text = String(d.user_message || '').trim();
const ocean = d.ocean || { O:0, C:0, E:0, A:0, N:0 };
const directives = d.directives || [];

function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }

function extractTopics(text) {
  const low = text.toLowerCase();
  const topics = [];
  const topicMap = {
    meditation: /(meditat|mindful|breathing exercise|zen|mantra)/,
    exercise: /(exercise|workout|gym|running|walk|yoga|sport|swim|hik)/,
    sleep: /(sleep|rest|nap|insomnia|tired|exhausted|bed)/,
    work: /(work|job|office|boss|colleague|career|project|deadline)/,
    family: /(family|parent|mother|father|mom|dad|sibling|brother|sister|child|kid|son|daughter)/,
    friends: /(friend|buddy|pal|mate|companion|social)/,
    health: /(health|doctor|hospital|sick|pain|illness|therapy|therapist|medication)/,
    nature: /(nature|garden|park|tree|flower|mountain|beach|ocean|river|outdoor)/,
    creativity: /(creat|art|music|paint|writ|draw|sing|danc|cook|craft)/,
    learning: /(learn|study|read|book|course|class|school|university)/,
    gratitude: /(grateful|thankful|appreciate|blessed|gratitude)/,
    calm: /(calm|peace|serene|tranquil|quiet|still|relax)/,
    energy: /(energy|energetic|alive|vibrant|motivated|excited|pumped)/,
    connection: /(connect|bond|relationship|love|close|together|belonging)/
  };
  for (const [topic, regex] of Object.entries(topicMap)) {
    if (regex.test(low)) topics.push(topic);
  }
  return topics;
}

function applyDirectiveStyle(base, directives, ocean) {
  let result = base;
  const E = Number(ocean.E || 0);
  const A = Number(ocean.A || 0);
  const N = Number(ocean.N || 0);
  const O = Number(ocean.O || 0);
  const C = Number(ocean.C || 0);
  const dStr = directives.join(' ').toLowerCase();

  if (dStr.includes('energetic') || dStr.includes('sociable')) {
    result = result.replace(/\.$/, '!').replace(/^(I |That |It )/, (m) => m);
  }
  if (dStr.includes('comfort') || dStr.includes('anxiet') || N < -0.2) {
    if (!result.includes('safe') && !result.includes('here for you')) {
      result += ' Know that this is a safe space, and I\'m here for you.';
    }
  }
  if ((dStr.includes('exploration') || dStr.includes('novelty') || O > 0.3) && !result.includes('curious') && !result.includes('explore')) {
    result += ' I\'m curious to explore this further with you.';
  }
  if ((dStr.includes('structured') || dStr.includes('organized') || C > 0.3) && !result.includes('step')) {
    result += ' Would it help to think about this step by step?';
  }
  return result;
}

function heuristicResponse(text, ocean, directives) {
  const low = text.toLowerCase();
  const E = Number(ocean.E || 0);
  const A = Number(ocean.A || 0);
  const N = Number(ocean.N || 0);
  const O = Number(ocean.O || 0);
  const C = Number(ocean.C || 0);
  const topics = extractTopics(text);

  const isGreeting = /(^|\s)(hi|hello|hey|how are you|what's up|good morning|good evening)/i.test(low) && text.length < 40;
  const isPositive = /(good|calm|great|happy|better|peace|grateful|appreciate|wonderful|fantastic|awesome|excited|love|enjoy)/i.test(low);
  const isNegative = /(low|sad|overwhelmed|anxious|stressed|tired|worried|afraid|depressed|frustrated|angry|upset|hurt|lonely|terrible|awful)/i.test(low);
  const isQuestion = /\?/.test(text);
  const isReflective = /(think|wonder|reflect|meaning|purpose|life|feel like|sometimes|realize|understand|aware)/i.test(low);
  const isAdvice = /(best way|should|recommend|suggest|how to|tip|advice|help me)/i.test(low);
  const isSharing = text.length > 80;

  if (isGreeting) {
    const greetings = [
      E > 0.3 ? `Hey there! Great to hear from you! How has your day been going? Anything on your mind you'd like to chat about?`
        : A > 0.2 ? `Hello! It's really nice to connect with you. How are you doing today? I'm here whenever you're ready to share.`
        : `Hi! Welcome — I'm glad you're here. How are things going for you today?`,
      `Hey! Good to see you. What's been on your mind lately?`,
      E > 0.3 ? `Hi there! Always nice to connect. What brings you here today?`
        : `Hello. I'm here and listening. What would you like to talk about?`
    ];
    return applyDirectiveStyle(pick(greetings), directives, ocean);
  }

  if (isAdvice && topics.length > 0) {
    const topic = topics[0];
    const topicResponses = {
      meditation: [
        `It sounds like you already have great insight into what works for you — meditation really can be transformative. How long have you been practicing? I'd love to hear about your experience with it.`,
        `You're absolutely right that meditation can be incredibly grounding. What type of meditation resonates most with you — guided, breath-focused, or something else?`,
        `That's a wonderful practice to have in your toolkit. Meditation has such deep benefits for both mind and body. Do you have a regular routine, or is it more spontaneous?`
      ],
      exercise: [
        `Movement really is such a powerful way to shift your energy. What kind of exercise do you find most enjoyable or effective for you?`,
        `You're onto something important there — physical activity can be one of the best things for our wellbeing. Is there a particular type of exercise that you find works best?`
      ],
      sleep: [
        `Rest is so fundamental to how we feel and function. What's your relationship with sleep been like recently?`,
        `That's such an important area to pay attention to. Good sleep really is the foundation of wellbeing. What does your wind-down routine look like?`
      ],
      nature: [
        `Being in nature really does have a special way of grounding us. What kinds of natural settings do you find most restorative?`,
        `There's something deeply healing about connecting with the natural world. Do you get to spend time outdoors regularly?`
      ]
    };
    const responses = topicResponses[topic] || [
      `That's a really insightful perspective on ${topic}. I'd love to hear more about your experience with it. What made you realize this?`,
      `You seem to have a thoughtful approach to ${topic}. How has this understanding shaped your daily life?`
    ];
    return applyDirectiveStyle(pick(responses), directives, ocean);
  }

  if (isNegative) {
    const empathyPool = [
      `I hear you, and it takes real courage to share when things feel heavy.`,
      `Thank you for being open about how you're feeling — that truly matters.`,
      `I can sense this is weighing on you, and I want you to know your feelings are completely valid.`,
      `It sounds like you're carrying a lot right now. I'm here to listen.`
    ];
    const supportPool = N < -0.2 ? [
      `You don't have to navigate this alone — that's what I'm here for.`,
      `Whatever you're going through, we can face it together at your pace.`,
      `Sometimes just having someone to listen can make things feel a little lighter.`
    ] : [
      `Let's take this one step at a time together.`,
      `I'm here to support you through this.`,
      `We can work through this — there's no rush.`
    ];
    const followUpPool = topics.length > 0 ? [
      `Can you tell me more about how ${topics[0]} has been affecting you?`,
      `What aspect of ${topics[0]} has been the most challenging?`,
      `How long have you been feeling this way about ${topics[0]}?`
    ] : [
      `Can you tell me more about what's been weighing on you?`,
      `What feels like the heaviest part of what you're experiencing?`,
      `When did you first start feeling this way?`,
      `What would feel most helpful for us to focus on together?`
    ];
    return applyDirectiveStyle(`${pick(empathyPool)} ${pick(supportPool)} ${pick(followUpPool)}`, directives, ocean);
  }

  if (isPositive) {
    const topicRef = topics.length > 0 ? topics[0] : null;
    if (topicRef) {
      const topicPositive = {
        calm: [
          `There's something really beautiful about finding that inner calm. It's not always easy to get there, so the fact that you're feeling it is worth celebrating. What's been helping you cultivate that sense of peace?`,
          `Feeling calm is such a gift to yourself. I'm curious — is this a feeling you've been actively working toward, or did it come naturally today?`,
          `That sense of calm sounds really grounding. What does it feel like in your body when you notice that stillness?`
        ],
        meditation: [
          `It sounds like your meditation practice is really paying off! That calm energy you're describing is exactly what consistent practice can bring. How has your practice evolved over time?`,
          `The peace that comes from meditation is so unique — it's like a calm that comes from within rather than from circumstances. What drew you to meditation in the first place?`
        ],
        gratitude: [
          `That spirit of gratitude you're expressing is really powerful. Research shows that noticing what we're thankful for literally rewires the brain toward positivity. What are you most grateful for today?`,
          `I love that you're in a space of appreciation right now. Gratitude has such a ripple effect on everything else. What's been standing out to you lately?`
        ],
        energy: [
          `I can really feel that energy coming through! There's something contagious about that kind of vitality. What's been fueling it?`,
          `That vibrant energy is wonderful. It sounds like you're really in a flow state. What's been driving that motivation?`
        ],
        connection: [
          `Those deep connections you're describing really are what make life rich. It sounds like you're in a space where you're open to that kind of vulnerability, which takes courage. What's been the most meaningful connection for you recently?`,
          `The desire for meaningful connection is so human and so important. It sounds like you're honoring that need in yourself. What kind of connections nourish you most?`
        ]
      };
      if (topicPositive[topicRef]) {
        return applyDirectiveStyle(pick(topicPositive[topicRef]), directives, ocean);
      }
    }
    const generalPositive = [
      `That's really wonderful to hear! What's been the highlight of this positive energy for you?`,
      `I can sense that good energy in what you're sharing! It's clear you're in a meaningful place right now. What do you think is contributing most to this feeling?`,
      `It sounds like you're in a really good headspace. Those moments are worth savoring. Is there something specific that shifted things for you?`,
      `What a great place to be in! I'm curious about what's been different lately that's contributing to this positive shift.`,
      `That positivity really comes through in your words. It's inspiring. What would you say has been the biggest factor?`
    ];
    return applyDirectiveStyle(pick(generalPositive), directives, ocean);
  }

  if (isSharing) {
    const shareResponses = [
      `Thank you for sharing all of that with me — I can tell this is something you've been thinking deeply about.${topics.length > 0 ? ` The way you describe ${topics[0]} really resonates.` : ''} What feels most important to you in all of this?`,
      `I really appreciate you opening up like this. There's a lot of depth in what you're saying.${topics.length > 0 ? ` I'm particularly struck by what you said about ${topics[0]}.` : ''} What part of this would you like to explore further?`,
      `Wow, it sounds like there's a lot going on for you — and the self-awareness you're showing is remarkable.${topics.length > 0 ? ` Tell me more about the ${topics[0]} aspect` : ' Tell me more about what feels most significant'} — I'd love to understand better.`
    ];
    return applyDirectiveStyle(pick(shareResponses), directives, ocean);
  }

  if (isReflective) {
    const reflections = [
      `Those are really thoughtful reflections. That kind of self-awareness is genuinely valuable.${topics.length > 0 ? ` What specifically about ${topics[0]} has been on your mind?` : ' What drew you to think about this?'}`,
      `I love that you're sitting with these deeper questions. It takes courage to look inward like that. What has this reflection been revealing to you?`,
      `There's something really meaningful about taking the time to reflect like this. What insights have been coming up for you?`
    ];
    return applyDirectiveStyle(pick(reflections), directives, ocean);
  }

  if (isQuestion) {
    const questionResponses = [
      `That's a really thoughtful question. I think the answer is unique to each person's journey.${topics.length > 0 ? ` When it comes to ${topics[0]}, ` : ' '}What's your own intuition telling you?`,
      `Great question! I'd love to explore that with you. What's been prompting you to think about this?`,
      `I appreciate you asking that. Before I share my thoughts, I'm curious — what's your gut feeling on it?`
    ];
    return applyDirectiveStyle(pick(questionResponses), directives, ocean);
  }

  const defaults = [
    `Thanks for sharing that with me.${topics.length > 0 ? ` I'd like to hear more about your experience with ${topics[0]}.` : ''} What feels most important to talk about right now?`,
    `I appreciate you opening up.${topics.length > 0 ? ` ${topics[0].charAt(0).toUpperCase() + topics[0].slice(1)} sounds like something meaningful to you.` : ''} Tell me more about what's on your mind.`,
    `That's interesting — I'd like to understand more about your perspective.${topics.length > 0 ? ` How has ${topics[0]} been part of your experience?` : ' What would be most helpful to explore together?'}`,
    `I hear you. What you're sharing matters.${topics.length > 0 ? ` Let's talk more about ${topics[0]} — ` : ' '}What aspect would you like to dive deeper into?`
  ];
  return applyDirectiveStyle(pick(defaults), directives, ocean);
}

let reply = '';
let genStatus = 'heuristic';
let genError = null;

try {
  const apiKey = process.env.NVIDIA_API_KEY || '';
  const apiUrl = process.env.NVIDIA_API_URL || 'https://integrate.api.nvidia.com/v1/chat/completions';
  const model = process.env.NVIDIA_MODEL || 'google/gemma-3-12b-it';

  if (apiKey && apiKey.length > 10) {
    const sysPrompt = `You are Big5Loop, a supportive, personality-aware caregiver assistant for Swiss healthcare.\n\nStyle directives based on the user's personality:\n${directives.map((d,i) => `${i+1}. ${d}`).join('\n')}\n\nRules:\n- Keep responses 2-4 sentences\n- Reference what the user specifically said\n- Be genuine, warm, and non-generic\n- Ask one follow-up question\n- Never start with 'I appreciate you sharing'`;
    const resp = await fetch(apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({ model, messages: [{ role: 'system', content: sysPrompt }, { role: 'user', content: text }], temperature: 0.7, max_tokens: 200 })
    });
    if (resp.ok) {
      const body = await resp.json();
      const content = body.choices?.[0]?.message?.content;
      if (content && content.length > 10) {
        reply = content;
        genStatus = 'nvidia';
      }
    } else {
      genError = `API ${resp.status}`;
    }
  }
} catch (e) {
  genError = e.message;
}

if (!reply) {
  reply = heuristicResponse(text, ocean, directives);
}

return [{ json: {
  ...d,
  reply: reply,
  generation: {
    api_status: genStatus,
    error: genError,
    directives_applied: directives,
    topics_detected: extractTopics(text)
  }
}}];

// ── STEP 5: FORMAT FINAL RESPONSE ──
const d = $input.first().json;

return [{ json: {
  session_id: d.session_id || '',
  message: {
    role: 'assistant',
    content: d.reply || 'How can I help you today?',
    timestamp: new Date().toISOString()
  },
  personality_state: {
    ocean: d.ocean || { O:0, C:0, E:0, A:0, N:0 },
    stable: false,
    confidence: d.detection?.confidence || {}
  },
  pipeline_status: {
    detector: d.detection?.api_status || 'unknown',
    generator: d.generation?.api_status || 'unknown'
  },
  debug: {
    detection_error: d.detection?.error || null,
    generation_error: d.generation?.error || null,
    directives: d.directives || [],
    turn_index: d.turn_index || 1
  }
}}];
